#!/bin/bash
set -e
GIT_DIR=/git/project
while read oldrev newrev refname; do
  branch=${refname#refs/heads/}
  case "$branch" in
    main) target=/var/www/main ;;
    dev)  target=/var/www/dev ;;
    *) continue ;;
  esac
  mkdir -p "$target"
  git --git-dir="$GIT_DIR" --work-tree="$target" checkout -f "$branch" -- .
done

#!/bin/bash
set -e
GIT_DIR=/git/project
while read oldrev newrev refname; do
  branch=${refname#refs/heads/}
  case "$branch" in
    main) target=/var/www/main ;;
    dev)  target=/var/www/dev ;;
    *) continue ;;
  esac
  mkdir -p "$target"
  git --git-dir="$GIT_DIR" --work-tree="$target" checkout -f "$branch" -- .
done

server {
    listen 8443 ssl;
    server_name localhost;

    ssl_certificate     /etc/nginx/ssl/self.crt;
    ssl_certificate_key /etc/nginx/ssl/self.key;

    location /dev/ {
        alias /var/www/dev/;
        index index.html;
    }

    location / {
        root /var/www/main;
        index index.html;
    }
}

